    // Embedded Android coordination is host-managed, so native calls are ordered off the JS thread.
    private val executor = Executors.newSingleThreadExecutor()

    override fun getName(): String = NAME

    override fun version(): String = UldrenLoomNative.nativeVersion()

    override fun blobDigest(bytes: ReadableArray): String {
        val out = ByteArray(bytes.size())
        for (i in 0 until bytes.size()) {
            out[i] = bytes.getInt(i).toByte()
        }
        return UldrenLoomNative.nativeBlobDigest(out)
    }

    override fun create(
        loomPath: String,
        profile: String,
        suite: String,
        passphrase: String,
        promise: Promise,
    ) {
        executor.execute {
            try {
                UldrenLoomNative.nativeCreate(loomPath, profile, suite, passphrase.encodeToByteArray())
                promise.resolve(null)
            } catch (e: Throwable) {
                promise.reject(e)
            }
        }
    }

    override fun createWithKek(
        loomPath: String,
        profile: String,
        suite: String,
        kek: ReadableArray,
        promise: Promise,
    ) {
        executor.execute {
            try {
                val out = ByteArray(kek.size())
                for (i in 0 until kek.size()) {
                    out[i] = kek.getInt(i).toByte()
                }
                UldrenLoomNative.nativeCreateWithKek(loomPath, profile, suite, out)
                promise.resolve(null)
            } catch (e: Throwable) {
                promise.reject(e)
            }
        }
    }

    // Convert a JS 0-255 number array into a ByteArray (encrypted-store key material).
    private fun keyBytes(arr: ReadableArray): ByteArray {
        val out = ByteArray(arr.size())
        for (i in 0 until arr.size()) {
            out[i] = arr.getInt(i).toByte()
        }
        return out
    }

    private fun resolveString(promise: Promise, call: () -> String) {
        executor.execute {
            try {
                promise.resolve(call())
            } catch (e: Throwable) {
                promise.reject(e)
            }
        }
    }

    private fun resolveBytes(promise: Promise, call: () -> ByteArray) {
        executor.execute {
            try {
                promise.resolve(bytesToArray(call()))
            } catch (e: Throwable) {
                promise.reject(e)
            }
        }
    }

    private fun aclScopeParts(scopes: ReadableArray): Pair<IntArray, Array<ByteArray>> {
        val kinds = IntArray(scopes.size())
        val prefixes = Array(scopes.size()) { ByteArray(0) }
        for (i in 0 until scopes.size()) {
            val value = scopes.getString(i) ?: throw IllegalArgumentException("ACL scope is null")
            val split = value.indexOf(':')
            if (split <= 0) {
                throw IllegalArgumentException("ACL scope must be kind:prefix")
            }
            kinds[i] = when (value.substring(0, split)) {
                "ref" -> 0
                "collection" -> 1
                "path" -> 2
                "key" -> 3
                "table" -> 4
                "exec" -> 5
                else -> throw IllegalArgumentException("unknown ACL scope kind")
            }
            prefixes[i] = value.substring(split + 1).encodeToByteArray()
        }
        return kinds to prefixes
    }

