    private fun bytesToArray(bytes: ByteArray): com.facebook.react.bridge.WritableArray {
        val arr = Arguments.createArray()
        for (b in bytes) {
            arr.pushInt(b.toInt() and 0xFF)
        }
        return arr
    }

    override fun docPutText(
        loomPath: String,
